mv_corr_pairs &lt;- as.data.frame(as.table(subtest_cov$correlation)) |&gt;
  rename(Subtest_A = Var1, Subtest_B = Var2, Correlation = Freq) |&gt;
  filter(Subtest_A &lt; Subtest_B) |&gt;
  mutate(
    Relation = case_when(
      abs(Correlation) &gt;= 0.80 ~ "高い重複（冗長の可能性）",
      abs(Correlation) &gt;= 0.50 ~ "関連あり（独立ではない）",
      TRUE ~ "ほぼ独立"
    ),
    Weighting_hint = case_when(
      abs(Correlation) &gt;= 0.80 ~ "両方を高重みにすると情報が重複する",
      abs(Correlation) &gt;= 0.50 ~ "バランスの取れた重み配分が安定しやすい",
      TRUE ~ "プログラム目標に応じて重み配分を決める"
    )
  )

mv_corr_pairs |&gt;
  gt() |&gt;
  tab_header(title = "サブテスト間相関の解釈と重み付けへの示唆") |&gt;
  fmt_number(columns = Correlation, decimals = 3) |&gt;
  cols_label(
    Subtest_A = "Subtest A", Subtest_B = "Subtest B",
    Correlation = "相関", Relation = "解釈", Weighting_hint = "重み付けの示唆")







